mapper.select:
/** UsptExpertReqstHistDao.selectList */ select expert_reqst_hist_id /** 전문가신청처리이력**/ ,expert_id /** 전문가ID**/ ,expert_reqst_process_sttus_cd /** 전문가신청처리상태코드(G:EXPERT_REQST_PROCESS_STTUS)**/ ,resn_cn /** 사유내용**/ ,creator_id /** 생성자ID(CMMT_MEMBER.MEMBER_ID)**/ ,created_dt /** 생성일시**/ from uspt_expert_reqst_hist where 1=1
and expert_acdmcr_id = #{expertReqstHistId}
and expert_id = #{expertId}

mapper.insert:
/** UsptExpertReqstHistDao.insert */
insert into uspt_expert_reqst_hist (
		 expert_reqst_hist_id
		,expert_id
		,expert_reqst_process_sttus_cd
		,resn_cn
		,creator_id
		,created_dt
	) values (
		 #{expertReqstHistId}
		,#{expertId}
		,#{expertReqstProcessSttusCd}
		,#{resnCn}
		,#{creatorId}
		,#{createdDt}
	)

mapper.update:
/** UsptExpertReqstHistDao.insert */
update uspt_expert_reqst_hist
     set expert_reqst_process_sttus_cd = #{expertReqstProcessSttusCd}
		,resn_cn                   = #{resnCn}
where expert_reqst_hist_id = #{expertReqstHistId}
   and  expert_id = #{expertId}

mapper.delete:
